// src/pages/blog/[slug].astro
import type { InferGetStaticParamsType, InferGetStaticPropsType } from 'astro';

export async function getStaticPaths() {
  const posts = await fetch('/api/posts').then(r => r.json());
  return posts.map((p: { slug: string; title: string }) => ({
    params: { slug: p.slug },
    props:  { title: p.title },
  }));
}

type Params = InferGetStaticParamsType<typeof getStaticPaths>; // { slug: string }
type Props  = InferGetStaticPropsType<typeof getStaticPaths>;  // { title: string }

const { slug } = Astro.params as Params;  // narrowed — no undefined
const { title } = Astro.props as Props;
---
<h1>{title}</h1>

// src/middleware.ts
import { defineMiddleware } from 'astro:middleware';
import * as Sentry from '@sentry/astro';

export const onRequest = defineMiddleware(async (ctx, next) => {
  const reqId = crypto.randomUUID();
  ctx.locals.requestId = reqId;

  return Sentry.withIsolationScope(async (scope) => {
    scope.setTag('requestId', reqId);
    scope.setTag('route', ctx.routePattern);
    const start = performance.now();
    const res = await next();
    console.log(JSON.stringify({
      method: ctx.request.method,
      path: ctx.url.pathname,
      status: res.status,
      ms: Math.round(performance.now() - start),
      reqId,
    }));
    return res;
  });
});

// src/middleware.ts
import { defineMiddleware, sequence } from 'astro:middleware';

const auth = defineMiddleware(async (ctx, next) => {
  const session = ctx.cookies.get('session')?.value;
  if (!session && ctx.url.pathname.startsWith('/dashboard')) {
    return ctx.redirect('/login');
  }
  ctx.locals.userId = session ?? null;
  return next();
});

const geo = defineMiddleware(async (ctx, next) => {
  const country = ctx.request.headers.get('cf-ipcountry') ?? 'US';
  ctx.locals.country = country;
  return next();
});

export const onRequest = sequence(auth, geo);
